/// <summary>Searches the web using DuckDuckGo and returns result snippets.</summary>
sealed class WebSearcher
{
    private static readonly HttpClient Http = new()
    {
        Timeout = TimeSpan.FromSeconds(15),
        DefaultRequestHeaders = { { "User-Agent", "ResearchAgent/1.0" } },
    };

    public async Task<string> SearchAsync(
        [Description("The search query to look up on the web")] string query)
    {
        Console.WriteLine($"  🔍 Searching: \"{query}\"");

        try
        {
            var encoded = Uri.EscapeDataString(query);
            var url = $"https://html.duckduckgo.com/html/?q={encoded}";
            var html = await Http.GetStringAsync(url);
            var snippets = ParseSnippets(html, maxResults: 5);

            if (snippets.Count == 0)
                return $"No results found for \"{query}\".";

            var sb = new StringBuilder();
            sb.AppendLine($"Search results for \"{query}\":\n");
            for (int i = 0; i < snippets.Count; i++)
            {
                sb.AppendLine($"{i + 1}. [{snippets[i].Title}]");
                sb.AppendLine($"   {snippets[i].Snippet}");
                if (!string.IsNullOrEmpty(snippets[i].Url))
                    sb.AppendLine($"   Source: {snippets[i].Url}");
                sb.AppendLine();
            }

            return sb.ToString();
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}";
        }
    }

    private static List<(string Title, string Snippet, string Url)> ParseSnippets(
        string html, int maxResults)
    {
        var results = new List<(string Title, string Snippet, string Url)>();

        // Parse DuckDuckGo HTML search result blocks
        var resultMarker = "class=\"result__body";
        var idx = 0;

        while (results.Count < maxResults && idx < html.Length)
        {
            idx = html.IndexOf(resultMarker, idx, StringComparison.Ordinal);
            if (idx < 0) break;

            var title = ExtractBetween(html, "class=\"result__a\"", "</a>", idx);
            var snippet = ExtractBetween(html, "class=\"result__snippet", "</a>", idx);
            var url = ExtractHref(html, "class=\"result__url", idx);

            title = StripTags(title);
            snippet = StripTags(snippet);
            url = StripTags(url).Trim();

            if (!string.IsNullOrWhiteSpace(title) || !string.IsNullOrWhiteSpace(snippet))
                results.Add((title, snippet, url));

            idx++;
        }

        return results;
    }

    private static string ExtractBetween(string html, string startMarker, string endTag, int searchFrom)
    {
        var start = html.IndexOf(startMarker, searchFrom, StringComparison.Ordinal);
        if (start < 0) return string.Empty;

        var tagClose = html.IndexOf('>', start);
        if (tagClose < 0) return string.Empty;

        var contentStart = tagClose + 1;
        var end = html.IndexOf(endTag, contentStart, StringComparison.Ordinal);
        if (end < 0) return string.Empty;

        return html[contentStart..end];
    }

    private static string ExtractHref(string html, string marker, int searchFrom)
    {
        var pos = html.IndexOf(marker, searchFrom, StringComparison.Ordinal);
        if (pos < 0) return string.Empty;

        var tagClose = html.IndexOf('>', pos);
        if (tagClose < 0) return string.Empty;

        var endTag = html.IndexOf("</a>", tagClose, StringComparison.Ordinal);
        if (endTag < 0) return string.Empty;

        return html[(tagClose + 1)..endTag];
    }

    private static string StripTags(string html)
    {
        if (string.IsNullOrEmpty(html)) return string.Empty;

        var sb = new StringBuilder(html.Length);
        var inTag = false;

        foreach (var c in html)
        {
            switch (c)
            {
                case '<': inTag = true; break;
                case '>': inTag = false; break;
                default:
                    if (!inTag) sb.Append(c);
                    break;
            }
        }

        return System.Net.WebUtility.HtmlDecode(sb.ToString()).Trim();
    }
}

/// <summary>In-memory notebook for collecting research notes.</summary>
sealed class ResearchNotebook
{
    private readonly List<(string Title, string Body)> _notes = [];

    public string AddNote(
        [Description("Short title for the note")] string title,
        [Description("Detailed content of the note")] string body)
    {
        _notes.Add((title, body));
        Console.WriteLine($"  📝 Note saved: \"{title}\"");
        return $"Note #{_notes.Count} saved: \"{title}\"";
    }

    public string GetNotes()
    {
        if (_notes.Count == 0)
            return "No notes have been taken yet.";

        var sb = new StringBuilder();
        sb.AppendLine($"=== Research Notes ({_notes.Count} total) ===\n");

        for (int i = 0; i < _notes.Count; i++)
        {
            sb.AppendLine($"--- Note {i + 1}: {_notes[i].Title} ---");
            sb.AppendLine(_notes[i].Body);
            sb.AppendLine();
        }

        return sb.ToString();
    }

    public void Clear() => _notes.Clear();
}

