using System.ComponentModel;
using System.Text;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using OpenAI;

// --- Configuration -----------------------------------------------------------

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

const string modelId = "gpt-4o-mini-2024-07-18";

// --- Tools -------------------------------------------------------------------

var notebook = new ResearchNotebook();
var webSearcher = new WebSearcher();

var tools = new AIFunction[]
{
    AIFunctionFactory.Create(
        webSearcher.SearchAsync,
        nameof(WebSearcher.SearchAsync),
        "Search the web for a query and return a list of result snippets."),

    AIFunctionFactory.Create(
        notebook.AddNote,
        nameof(ResearchNotebook.AddNote),
        "Save a research note with a title and body for later summarization."),

    AIFunctionFactory.Create(
        notebook.GetNotes,
        nameof(ResearchNotebook.GetNotes),
        "Retrieve all research notes collected so far."),
};

// --- Agent setup -------------------------------------------------------------

IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

var agent = new ChatClientAgent(chatClient, "ResearchAgent")
{
    Instructions = "You are a research assistant. Given a topic, you search the web for " +
        "relevant information and take structured notes. After gathering enough " +
        "information (aim for 3-5 searches), retrieve your notes and produce a " +
        "concise summary with key findings and sources.",
    DefaultOptions = new AgentRunOptions
    {
        ModelOptions = new ChatOptions
        {
            Temperature = 0f,
            MaxOutputTokens = 2048,
            Tools = [.. tools],
        },
    },
};

// --- Main loop ---------------------------------------------------------------

Console.WriteLine("╔══════════════════════════════════════╗");
Console.WriteLine("║       AI Research Agent (MAF)        ║");
Console.WriteLine("╚══════════════════════════════════════╝");
Console.WriteLine("Enter a topic to research (or 'quit' to exit):\n");

while (true)
{
    Console.Write("Topic> ");
    var topic = Console.ReadLine()?.Trim();

    if (string.IsNullOrEmpty(topic) || topic.Equals("quit", StringComparison.OrdinalIgnoreCase))
        break;

    notebook.Clear();
    Console.WriteLine($"\nResearching: {topic}\n");

    var messages = new List<ChatMessage>
    {
        new(ChatRole.User,
            $"Research the following topic thoroughly: \"{topic}\". " +
            "Search for multiple angles, save key findings as notes, " +
            "then retrieve your notes and write a final summary."),
    };

    try
    {
        await foreach (var update in agent.RunStreamingAsync(messages))
        {
            if (!string.IsNullOrWhiteSpace(update.Text))
            {
                Console.Write(update.Text);
            }
        }

        Console.WriteLine("\n");
    }
    catch (Exception ex)
    {
        Console.WriteLine($"\nError: {ex.Message}\n");
    }
}

Console.WriteLine("Goodbye!");

// =============================================================================
// Tool implementations
// =============================================================================

sealed class WebSearcher
{
    private static readonly HttpClient Http = new()
    {
        Timeout = TimeSpan.FromSeconds(15),
        DefaultRequestHeaders = { { "User-Agent", "ResearchAgent/1.0" } },
    };

    public async Task<string> SearchAsync(
        [Description("The search query to look up on the web")] string query)
    {
        Console.WriteLine($"  🔍 Searching: \"{query}\"");

        try
        {
            var encoded = Uri.EscapeDataString(query);
            var url = $"https://html.duckduckgo.com/html/?q={encoded}";
            var html = await Http.GetStringAsync(url);
            var snippets = ParseSnippets(html, maxResults: 5);

            if (snippets.Count == 0)
                return $"No results found for \"{query}\".";

            var sb = new StringBuilder();
            sb.AppendLine($"Search results for \"{query}\":\n");
            for (int i = 0; i < snippets.Count; i++)
            {
                sb.AppendLine($"{i + 1}. [{snippets[i].Title}]");
                sb.AppendLine($"   {snippets[i].Snippet}");
                if (!string.IsNullOrEmpty(snippets[i].Url))
                    sb.AppendLine($"   Source: {snippets[i].Url}");
                sb.AppendLine();
            }

            return sb.ToString();
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}";
        }
    }

    private static List<(string Title, string Snippet, string Url)> ParseSnippets(
        string html, int maxResults)
    {
        var results = new List<(string Title, string Snippet, string Url)>();
        var resultMarker = "class=\"result__body";
        var idx = 0;

        while (results.Count < maxResults && idx < html.Length)
        {
            idx = html.IndexOf(resultMarker, idx, StringComparison.Ordinal);
            if (idx < 0) break;

            var title = ExtractBetween(html, "class=\"result__a\"", "</a>", idx);
            var snippet = ExtractBetween(html, "class=\"result__snippet", "</a>", idx);
            var url = ExtractHref(html, "class=\"result__url", idx);

            title = StripTags(title);
