Console.WriteLine("╔══════════════════════════════════════╗");
Console.WriteLine("║       AI Research Agent (MAF)        ║");
Console.WriteLine("╚══════════════════════════════════════╝");
Console.WriteLine("Enter a topic to research (or 'quit' to exit):\n");

while (true)
{
    Console.Write("Topic> ");
    var topic = Console.ReadLine()?.Trim();

    if (string.IsNullOrEmpty(topic) || topic.Equals("quit", StringComparison.OrdinalIgnoreCase))
        break;

    notebook.Clear();
    Console.WriteLine($"\nResearching: {topic}\n");

    var messages = new List<ChatMessage>
    {
        new(ChatRole.User,
            $"Research the following topic thoroughly: \"{topic}\". " +
            "Search for multiple angles, save key findings as notes, " +
            "then retrieve your notes and write a final summary."),
    };

    try
    {
        await foreach (var update in agent.RunStreamingAsync(messages, chatOptions))
        {
            if (!string.IsNullOrWhiteSpace(update.Text))
            {
                Console.Write(update.Text);
            }
        }

        Console.WriteLine("\n");
    }
    catch (Exception ex)
    {
        Console.WriteLine($"\nError: {ex.Message}\n");
    }
}

Console.WriteLine("Goodbye!");

